param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId)
$ErrorActionPreference='Stop';$target='macd';$runtime='NoraPhase2MacdRuntimeV3.mqh';$tester='NoraPhase2MacdTesterCanaryV3.mq5';$editor='C:\Program Files\Darwinex MetaTrader 5\MetaEditor64.exe';$expectedVersion='5.0.0.5836';$root="$env:USERPROFILE\NoraPhase2U";$run=Join-Path $root $RunId
function Hash($p){(Get-FileHash $p -Algorithm SHA256).Hash.ToLowerInvariant()};New-Item -ItemType Directory -Force $run|Out-Null;$source=Join-Path $run 'source';New-Item -ItemType Directory -Force $source|Out-Null;$log=Join-Path $run 'compile.log';$ex5=Join-Path $source $tester.Replace('.mq5','.ex5')
$r=[ordered]@{contract_version='nora.phase2.compiler_record_v2';compiler_policy_version='nora.metaeditor_cli_success_v1';target_identifier=$target;metaeditor_executable_path=$editor;metaeditor_version=$null;source_runtime_path=('source/'+$runtime);source_runtime_sha256=$null;tester_source_path=('source/'+$tester);tester_source_sha256=$null;command=$null;arguments=@();started_utc=(Get-Date).ToUniversalTime().ToString('o');raw_process_exit_status=$null;normalized_exit_interpretation='rejected';exit_interpretation_reason=$null;completion_state='incomplete';compiler_success=$false;warning_count=0;warnings=@();error_count=0;errors=@();compiler_log_relative_path='compile.log';compiler_log_sha256=$null;compiler_log_complete=$false;expected_ex5_relative_path=('source/'+$tester.Replace('.mq5','.ex5'));expected_ex5_absolute_path=$ex5;preexisting_ex5=$false;ex5_exists=$false;ex5_creation_utc=$null;ex5_modification_utc=$null;ex5_size=$null;ex5_sha256=$null;corroborating_checks=@{};failure_reason=$null}
try {foreach($n in @($runtime,$tester)){if(!(Test-Path (Join-Path $IncomingRoot $n))){throw "missing source: $n"};Copy-Item (Join-Path $IncomingRoot $n) (Join-Path $source $n) -Force};$program=Join-Path $source $tester;$r.source_runtime_sha256=Hash (Join-Path $source $runtime);$r.tester_source_sha256=Hash $program;if(!(Test-Path $editor)){throw 'missing compiler'};$r.metaeditor_version=(Get-Item $editor).VersionInfo.FileVersion;if($r.metaeditor_version -ne $expectedVersion){throw 'unexpected MetaEditor version'};if(Test-Path $ex5){$r.preexisting_ex5=$true;Remove-Item $ex5 -Force};$args=@('/compile:"'+$program+'"','/log:"'+$log+'"');$r.arguments=$args;$r.command=$editor+' '+($args -join ' ');$start=Get-Date;$p=Start-Process -FilePath $editor -ArgumentList $args -PassThru;$p.WaitForExit();$r.raw_process_exit_status=$p.ExitCode;if(!(Test-Path $log)){throw 'missing compiler log'};$r.compiler_log_sha256=Hash $log;$lines=Get-Content $log;$r.warnings=@($lines|Where-Object {$_ -match '(?i)\bwarning\b'});$r.errors=@($lines|Where-Object {$_ -match '(?i)\berror\b'});$r.warning_count=$r.warnings.Count;$r.error_count=$r.errors.Count;$r.compiler_log_complete=($lines -match 'Result:') -and ($lines -match [regex]::Escape($program));$r.corroborating_checks=[ordered]@{version=($r.metaeditor_version -eq $expectedVersion);log_complete=$r.compiler_log_complete;clean_log=($r.error_count -eq 0 -and $r.warning_count -eq 0);source_binding=($lines -match [regex]::Escape($program));expected_ex5_path=$true};if(!(Test-Path $ex5)){throw 'missing EX5'};$item=Get-Item $ex5;if($item.LastWriteTimeUtc -lt $start.ToUniversalTime()){throw 'stale EX5'};$r.ex5_exists=$true;$r.ex5_creation_utc=$item.CreationTimeUtc.ToString('o');$r.ex5_modification_utc=$item.LastWriteTimeUtc.ToString('o');$r.ex5_size=$item.Length;$r.ex5_sha256=Hash $ex5;if($r.raw_process_exit_status -eq 0){$r.normalized_exit_interpretation='accepted_zero';$r.exit_interpretation_reason='zero exit and corroborating checks'}elseif($r.raw_process_exit_status -eq 1 -and $r.corroborating_checks.version -and $r.corroborating_checks.log_complete -and $r.corroborating_checks.clean_log -and $r.ex5_exists){$r.normalized_exit_interpretation='accepted_metaeditor_5836_one';$r.exit_interpretation_reason='build 5.0.0.5836 exit 1 corroborated by clean complete log and fresh EX5'}else{throw 'unexpected or uncorroborated compiler exit'};$r.completion_state='completed';$r.compiler_success=$true}catch{$r.failure_reason=$_.Exception.Message;$r.completion_state='failed'}finally{$r.completed_utc=(Get-Date).ToUniversalTime().ToString('o');$r|ConvertTo-Json -Depth 10|Set-Content (Join-Path $run 'compile.json') -Encoding utf8};if(!$r.compiler_success){exit 2}
